                this.updateDisplay();
            }

            formatResult(result) {
                let resultStr = result.toString();
                if (resultStr.length &lt;= 9) return result;

                if (Math.abs(result) &gt;= 1e9 || (Math.abs(result) &lt; 1e-4 &amp;&amp; result !== 0)) {
                    return result.toExponential(2);
                }

                const decimalPlaces = Math.max(0, 8 - Math.floor(Math.log10(Math.abs(result))));
                resultStr = result.toFixed(decimalPlaces);
                return resultStr.length &gt; 9 ? result.toExponential(2) : parseFloat(resultStr);
            }

            clear() {
                this.currentInput = &#039;0&#039;;
                this.previousInput = &#039;&#039;;
                this.operator = &#039;&#039;;
                this.shouldResetInput = false;
                this.updateDisplay();
            }

            deleteLast() {
                if (this.shouldResetInput) return;
                if (this.currentInput.length &lt;= 1 || (this.currentInput.length === 2 &amp;&amp; this.currentInput.startsWith(&#039;-&#039;))) {
                    this.currentInput = &#039;0&#039;;
                } else {
                    this.currentInput = this.currentInput.slice(0, -1);
                }
                this.updateDisplay();
            }

            updateDisplay() {
                let displayText = this.currentInput;
                if (displayText.length &gt; 9 &amp;&amp; displayText !== &#039;Error&#039;) {
                    displayText = this.formatResult(parseFloat(displayText));
                }
                this.display.textContent = displayText.toString();
            }
        }

        new Calculator();

من برای این تجربه Qwen را انتخاب کردم چون علاوه بر اینکه بصورت رایگان در دسترس قرار دارد در مد Web dev امکان پیش نمایش کد حاصل را نیز بلافاصله فراهم میکند. همچنین می توانید کد تولید شده را ذیل دامنه qwen.ai به اشتراک بگذارید. این تجربه ساده می تواند شروع یک جهش بزرگ برای علاقمندان به برنامه نویسی بویژه نوجوانان و جوانان باشد. فراموش نکنیم که خواندن کدهای نوشته شده و تحلیل آن یکی از بهترین روشهای یادگیری و تعمیق دانسته های برنامه نویسان است.
اما همیشه مسئله به همین سادگی حل نمی شود. هر چقدر ساختار برنامه کاربردی نهایی پیچیده تر باشد شیوه طراحی پرامت نیز پیچیده تر می شود. بعلاوه چت باتها در اصلاح مکرر پاسخها هنوز محدودیتهای دارند بنابراین استفاده مستقیم از آنها گاهی اوقات کار را دشوار و نتیجه را دور از انتظار می کند. به همین دلیل ابزارهای اختصاصی برای این منظور توسعه داده شده است. بنابراین اگر قصد ساخت برنامه های کاربردی مفصل و پیچیده تری دارید بهتر است از ابزارهایی مانند Github Copilot یا Trea.ai استفاده کنید.
ساختار یک پرامت حرفه ای
برای داشتن یک خروجی مطلوب باید دستوراتی واضح و دقیق دارای ساختار استاندارد طراحی کرد. این کار خود یک تخصص حرفه ای است و امروزه به مهندسی پرامت مشهور شده است. ساختار یک پرامت مناسب برای کد نویسی معمولاً با توصیف هدف کلی پروژه آغاز می‌شود (مثلاً «ساخت یک برنامه مدیریت وظایف با رابط کاربری تعاملی»)، سپس به جزئیات عملکردها، ساختار داده‌ها و تعاملات کاربر پرداخته می شود. در ادامه باید فناوری‌ها و فریم‌ورک‌های مورد استفاده (مانند React، Vue یا Node.js) به‌وضوح مشخص شوند تا مدل در همان مسیر فنی پیش برود. ذکر لحن مورد انتظار کد (مثلاً ماژولار، دارای کامنت، یا بهینه برای مرورگرهای مدرن) و تعیین نحوه خروجی (یک فایل واحد، پروژه پوشه‌بندی‌شده یا فقط بخش خاصی از کد) نیز ضروری است. در نهایت، افزودن محدودیت‌ها و معیارهای کنترل کیفیت مانند امنیت، سرعت بارگذاری یا قابلیت نگهداری. اگر به مبحث مهندسی پرامت و ساختار یک دستور حرفه ای علاقمندید مقالات بعدی را از دست ندهید.
در اینجا و صرفاً جهت آشنایی خواننده با مقدمه موضوع به اختصار به اجزاء یک پرامت مناسب برای کد نویسی اشاره می کنم.
تعریف نقش (Role): مشخص کردن دقیق تخصص و وظیفه مدل.
توصیف کلی پروژه (Project Overview): هدف اصلی برنامه و معرفی کاربران نهایی. چه مشکلی قرار است حل ‌شود یا چه قابلیتهایی قرار است توسعه داده شود.
جزئیات عملکردی (Functional Requirements): فهرست قابلیت‌ها و رفتارهای اصلی برنامه، تعاملات کاربر (ورود داده، کلیک، فیلتر، جست‌وجو و غیره)، نحوه نمایش و به‌روزرسانی داده‌ها در رابط کاربری.
تکنولوژی‌ها و فریم‌ورک‌ها (Tech Stack): زبان‌ها و کتابخانه‌ها (JavaScript, HTML, CSS) فریم‌ورک‌های پیشنهادی (React, Vue, Node.js, Express و غیره)، وابستگی‌ها یا APIهای خارجی مورد نیاز.
ساختار کد و سازمان پروژه (Code Structure): نحوه تقسیم‌بندی فایل‌ها و پوشه‌ها، معماری کلی (Component-Based, MVC, SPA و…)، استانداردهای کدنویسی (ماژولار، دارای کامنت، استفاده از ES6+).
خروجی مورد انتظار (Expected Output): نوع خروجی (کد کامل پروژه، فقط بخش خاصی مثل UI یا API)، قالب تحویل خروجی (یک فایل، پوشه پروژه بصورت فشرده، یا بلوک کد)، سطح جزئیات مورد انتظار (کد خام یا همراه با توضیحات).
محدودیت‌ها و معیارهای کیفیت (Constraints &amp; Quality Criteria): عملکرد و سرعت بارگذاری، امنیت و اعتبارسنجی داده‌ها، قابلیت نگهداری و توسعه در آینده.
ادامه بازی
بد نیست یک مثال حرفه ای را هم با هم ببینیم. فرض کنید می خواهیم یک برنامه دسکتاپ برای مدیریت وظایف طراحی کنید. پرامت زیر می تواند یک نمونه مناسب باشد.

توصیف کلی پروژه (Project Overview):
می‌خواهم یک برنامه دسکتاپ مدیریت وظایف (ToDo List) برای سیستم‌عامل ویندوز بسازم.
کاربر بتواند وظایف خود را اضافه، ویرایش و حذف کرده و کارهای انجام شده را بتواند علامت‌گذاری کند.
رابط کاربری برنامه باید راست‌به‌چپ و کاملاً فارسی باشد.
جزئیات عملکردی (Functional Requirements):
