console.log(typeof num === &quot;number&quot; &amp;&amp; !isNaN(num)); // true

// تابع چندمنظوره برای بررسی نوع
function getType(value) {
    if (value === null) return &quot;null&quot;;
    if (Array.isArray(value)) return &quot;array&quot;;
    return typeof value;
}

