بخش ۵: اعداد: عملیات پایه و شیء Math (Numbers: Basic Operations and Math Object)
اعداد از پایه‌ای‌ترین انواع داده در جاوااسکریپت هستند. درک عمیق نحوه کار با اعداد و شیء Math برای انجام محاسبات پیچیده ضروری است.
مفاهیم کلیدی:
۱. انواع اعداد در جاوااسکریپت:

اعداد صحیح (Integer): 42
اعداد اعشاری (Float): 3.14
نماد علمی (Scientific): 1.2e3 (برابر با 1200)
مقادیر خاص: Infinity, -Infinity, NaN

let integer = 42;
let float = 3.14;
let scientific = 1.2e3;
let infinity = 5 / 0;
let notANumber = &quot;abc&quot; / 2;

console.log(scientific); // 1200
console.log(infinity);   // Infinity
console.log(notANumber); // NaN
۲. متدهای مهم اعداد:
let num = 3.14159;

// تبدیل به رشته با اعشار مشخص
console.log(num.toFixed(2)); // &quot;3.14&quot;

// تبدیل به رشته در مبنای مختلف
console.log((255).toString(16)); // &quot;ff&quot;

// بررسی NaN
console.log(isNaN(&quot;abc&quot;)); // true
console.log(Number.isNaN(&quot;abc&quot;)); // false (متد جدیدتر)

// تبدیل رشته به عدد
console.log(parseInt(&quot;123abc&quot;)); // 123
console.log(parseFloat(&quot;3.14abc&quot;)); // 3.14
۳. شیء Math برای عملیات پیشرفته:
// ثابت‌های ریاضی
console.log(Math.PI); // 3.141592653589793
console.log(Math.E);  // 2.718281828459045

// متدهای گرد‌کردن
console.log(Math.round(4.7));  // 5
console.log(Math.floor(4.7));  // 4
console.log(Math.ceil(4.2));   // 5

// متدهای محاسباتی
console.log(Math.max(1, 5, 10)); // 10
console.log(Math.min(1, 5, 10)); // 1
console.log(Math.sqrt(16));     // 4
console.log(Math.pow(2, 3));    // 8

// اعداد تصادفی
console.log(Math.random()); // عددی بین 0 تا 1
۴. تولید عدد تصادفی در بازه مشخص:
// تولید عدد تصادفی بین min و max (شامل خود min و max)
function getRandomInt(min, max) {
    return Math.floor(Math.random() * (max - min + 1)) + min;
}

